try {
  const body = $input.first().json.body || $input.first().json;
  const required = ['job_id', 'customer_name', 'customer_email', 'job_type', 'technician_name', 'labor_hours', 'labor_rate', 'materials_cost'];
  const missing = required.filter(f => body[f] === undefined || body[f] === null || body[f] === '');
  if (missing.length > 0) {
    throw new Error('Missing required fields: ' + missing.join(', '));
  }
  const labor_hours = Number(body.labor_hours);
  const labor_rate = Number(body.labor_rate);
  const materials_cost = Number(body.materials_cost);
  const labor_total = labor_hours * labor_rate;
  const materials_markup = materials_cost * 0.15;
  const job_total = labor_total + materials_cost + materials_markup;
  const is_emergency = body.is_emergency === true || body.is_emergency === 'true';
  const priority = is_emergency ? 'EMERGENCY' : 'STANDARD';
  const ts = body.completion_timestamp || new Date().toISOString();
  const dateObj = new Date(ts);
  const completion_date = dateObj.toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });
  return [{ json: { job_id: body.job_id, customer_name: body.customer_name, customer_email: body.customer_email, customer_phone: body.customer_phone || '', job_type: body.job_type, technician_name: body.technician_name, address: body.address || '', job_description: body.job_description || '', labor_hours, labor_rate, materials_cost, labor_total, materials_markup, job_total: Math.round(job_total * 100) / 100, is_emergency, priority, completion_timestamp: ts, completion_date } }];
} catch (err) {
  throw new Error('Parse & Validate failed: ' + err.message);
}

try {
  const d = $input.first().json;
  const lines = [
    '======= INVOICE - ' + d.job_type.toUpperCase() + ' SERVICE =======',
    '',
    'Job ID:       ' + d.job_id,
    'Date:         ' + d.completion_date,
    'Technician:   ' + d.technician_name,
    'Customer:     ' + d.customer_name,
    'Address:      ' + d.address,
    '',
    '--- DESCRIPTION ---',
    d.job_description,
    '',
    '--- LINE ITEMS ---',
    'Labor:              ' + d.labor_hours + ' hrs @ $' + d.labor_rate.toFixed(2) + '/hr    $' + d.labor_total.toFixed(2),
    'Materials:                                $' + d.materials_cost.toFixed(2),
    'Materials Markup (15%):                   $' + d.materials_markup.toFixed(2),
    '-------------------------------------------',
    'TOTAL DUE:                                $' + d.job_total.toFixed(2),
    '===========================================',
    '',
    'Payment due within 30 days.',
    'For questions, contact us at (212) 555-0100.',
    'Thank you for choosing our services!'
  ];
  return [{ json: { ...d, invoice_text: lines.join('\n'), invoice_generated: true } }];
} catch (err) {
  throw new Error('Build Invoice failed: ' + err.message);
}

try {
  const d = $input.first().json;
  const prefix = d.subject_prefix || '';
  const subject = prefix + 'Invoice - ' + d.job_type + ' Service - ' + d.customer_name;
  const emailBody = 'Dear ' + d.customer_name + ',\n\nThank you for choosing our ' + d.job_type.toLowerCase() + ' services. Please find your invoice details below.\n\n' + d.invoice_text + '\n\nBest regards,\n' + d.technician_name + '\nOpticfy Demo - ' + d.technician_name;
  return [{ json: { ...d, email_subject: subject, email_body: emailBody, invoice_email_sent: true } }];
} catch (err) {
  throw new Error('Send Invoice Email failed: ' + err.message);
}

try {
  const d = $input.first().json;
  const csvRow = [d.completion_date, d.job_id, d.customer_name, d.customer_email, d.job_type, d.technician_name, d.address, d.job_total.toFixed(2), d.is_emergency ? 'Y' : 'N', d.invoice_email_sent ? 'Y' : 'N', 'Complete'].join(' | ');
  return [{ json: { ...d, job_logged: true, csv_row: csvRow } }];
} catch (err) {
  throw new Error('Log Job to CSV failed: ' + err.message);
}

try {
  const d = $input.first().json;
  const subject = 'How did we do today, ' + d.customer_name + '?';
  const body = 'Hi ' + d.customer_name + ',\n\nI just wanted to personally thank you for trusting us with your ' + d.job_type.toLowerCase() + ' work today. It was a pleasure taking care of things at ' + d.address + '.\n\nIf you have a moment, a quick Google review would mean the world to our team - it helps other homeowners find reliable service: https://g.page/YOUR-BUSINESS/review\n\nThanks again,\n' + d.technician_name;
  return [{ json: { ...d, review_subject: subject, review_body: body, review_request_sent: true } }];
} catch (err) {
  throw new Error('Send Review Request failed: ' + err.message);
}

try {
  const d = $input.first().json;
  const actions = ['parse_validate', 'build_invoice', 'emergency_check', 'send_invoice_email', 'log_job_csv', 'wait_cooldown', 'send_review_request', 'upsell_check'];
  return [{ json: { workflow_status: 'success', timestamp: new Date().toISOString(), job_id: d.job_id, customer_name: d.customer_name, job_type: d.job_type, job_total: d.job_total, priority: d.priority, upsell_opportunity: d.upsell_opportunity || false, upsell_note: d.upsell_note || '', actions_taken: actions, email_subject: d.email_subject, review_subject: d.review_subject, csv_row: d.csv_row } }];
} catch (err) {
  throw new Error('Final Status failed: ' + err.message);
}

try {
  const error = $input.first().json;
  const execution = error.execution || {};
  const lastNode = execution.lastNodeExecuted || 'unknown';
  const errorMsg = execution.error ? execution.error.message : 'Unknown error';
  let jobId = 'unknown';
  try {
    const data = execution.data;
    if (data && data.resultData && data.resultData.runData) {
      const webhookData = data.resultData.runData['Webhook: Job Complete'];
      if (webhookData && webhookData[0] && webhookData[0].data && webhookData[0].data.main && webhookData[0].data.main[0]) {
        jobId = webhookData[0].data.main[0][0].json.body.job_id || 'unknown';
      }
    }
  } catch(e) {}
  return [{ json: { error_type: 'workflow_failure', failed_node: lastNode, error_message: errorMsg, job_id: jobId, timestamp: new Date().toISOString() } }];
} catch (err) {
  return [{ json: { error_type: 'error_handler_failure', error_message: err.message, timestamp: new Date().toISOString() } }];
}
